                data.prompt += "<s>";
                first_user = false;
            }
            std::string inst_content = content;
            if (!system_prompt.empty()) {
                inst_content = system_prompt + "\n" + content;
                system_prompt.clear();
            }
            data.prompt += "[INST] " + inst_content + " [/INST]";
        } else if (role == "assistant") {
            data.prompt += " " + content + "</s>";
        }
    }

    data.format = COMMON_CHAT_FORMAT_CONTENT_ONLY;

    return data;
}

